// cmd/fdb-wire-codegen generates Go structs + MarshalFDB/UnmarshalFDB methods
// from the per-message JSON schema files in pkg/fdbgo/wire/schema/.
//
// Usage: fdb-wire-codegen -schema=<dir> -out=<dir> [-messages=Msg1,Msg2,...]
//
// If -messages is not specified, generates all messages.
// Generated files go into the output directory, one file per message.

package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"text/template"
	"unicode"
)

type MessageDef struct {
	Name           string     `json:"name"`
	FileIdentifier uint32     `json:"file_identifier"`
	FDBVersion     string     `json:"fdb_version"`
	ReplyType      string     `json:"reply_type"`
	SourceFile     string     `json:"source_file"`
	VTable         []uint16   `json:"vtable"`
	Fields         []FieldDef `json:"fields"`
}

type FieldDef struct {
	Name          string `json:"name"`
	CppType       string `json:"cpp_type"`
	Type          string `json:"type"`
	VTableSlot    int    `json:"vtable_slot"`
	WireSize      uint32 `json:"wire_size"`
	WireAlignment uint32 `json:"wire_alignment"`
	Inline        bool   `json:"inline"`
}

// goFieldName converts a C++ field name to Go exported name.
func goFieldName(name string) string {
	if name == "" {
		return ""
	}
	// Strip array indexing: "part[0]" → "Part0"
	name = strings.ReplaceAll(name, "[", "")
	name = strings.ReplaceAll(name, "]", "")
	// Strip base class prefix: "LoadBalancedReply::penalty" → "Penalty"
	if idx := strings.LastIndex(name, "::"); idx >= 0 {
		name = name[idx+2:]
	}
	runes := []rune(name)
	runes[0] = unicode.ToUpper(runes[0])
	return string(runes)
}

// goType maps a schema field to its Go type.
func goType(f FieldDef) string {
	switch f.Type {
	case "scalar":
		return goScalarType(f.CppType, f.WireSize)
	case "bytes":
		return "[]byte"
	case "vector":
		return "[]byte" // raw for now, typed later
	case "optional":
		return "[]byte" // raw optional, typed later
	case "struct":
		return "[]byte" // raw nested struct, typed later
	case "arena":
		return "" // skip
	default:
		return "[]byte"
	}
}

func goScalarType(cppType string, wireSize uint32) string {
	switch cppType {
	case "bool":
		return "bool"
	case "double":
		return "float64"
	}
	switch wireSize {
	case 1:
		if strings.HasPrefix(cppType, "int8") {
			return "int8"
		}
		return "uint8"
	case 2:
		if strings.HasPrefix(cppType, "int16") {
			return "int16"
		}
		return "uint16"
	case 4:
		if strings.Contains(cppType, "uint") {
			return "uint32"
		}
		return "int32"
	case 8:
		if strings.Contains(cppType, "uint") {
			return "uint64"
		}
		if cppType == "double" {
			return "float64"
		}
		return "int64"
	default:
		return "int64"
	}
}

// readerMethod returns the Reader method name for a field.
func readerMethod(f FieldDef) string {
	switch f.Type {
	case "bytes", "vector", "struct":
		return "ReadBytes"
	case "optional":
		return "" // optionals are complex, handled separately
	case "scalar":
		gt := goScalarType(f.CppType, f.WireSize)
		switch gt {
		case "bool":
			return "ReadBool"
		case "int8":
			return "ReadInt8"
		case "uint8":
			return "ReadUint8"
		case "int16":
			return "ReadInt16"
		case "uint16":
			return "ReadUint16"
		case "int32":
			return "ReadInt32"
		case "uint32":
			return "ReadUint32"
		case "int64":
			return "ReadInt64"
		case "uint64":
			return "ReadUint64"
		case "float64":
			return "ReadFloat64"
		}
	}
	return ""
}

// writerMethod returns the ObjectWriter method name for a field.
func writerMethod(f FieldDef) string {
	switch f.Type {
	case "bytes", "vector", "struct":
		return "WriteBytes"
	case "optional":
		return "" // handled separately
	case "scalar":
		gt := goScalarType(f.CppType, f.WireSize)
		switch gt {
		case "bool":
			return "WriteBool"
		case "int8":
			return "WriteInt8"
		case "uint8":
			return "WriteUint8"
		case "int16":
			return "WriteInt16"
		case "uint16":
			return "WriteUint16"
		case "int32":
			return "WriteInt32"
		case "uint32":
			return "WriteUint32"
		case "int64":
			return "WriteInt64"
		case "uint64":
			return "WriteUint64"
		case "float64":
			return "WriteFloat64"
		}
	}
	return ""
}

var messageTmpl = template.Must(template.New("message").Funcs(template.FuncMap{
	"goFieldName":  goFieldName,
	"goType":       goType,
	"readerMethod": readerMethod,
	"writerMethod": writerMethod,
	"vtableOffset": func(m MessageDef, slot int) uint16 {
		idx := slot + 2
		if idx < len(m.VTable) {
			return m.VTable[idx]
		}
		return 0
	},
	"maxFieldAlign": func(m MessageDef) int {
		max := 4
		for _, f := range m.Fields {
			if int(f.WireAlignment) > max {
				max = int(f.WireAlignment)
			}
		}
		return max
	},
}).Parse(`// Code generated by fdb-wire-codegen from {{ .SourceFile }}. DO NOT EDIT.
// FDB version: {{ .FDBVersion }}

package protocol

import "github.com/birdayz/fdb-record-layer-go/pkg/fdbgo/wire"

const {{ .Name }}_FileIdentifier uint32 = {{ .FileIdentifier }}

var {{ .Name }}_VTable = wire.VTable{ {{- range $i, $v := .VTable }}{{ if $i }}, {{ end }}{{ $v }}{{ end -}} }

// {{ .Name }} — {{ .SourceFile }}
type {{ .Name }} struct {
{{- range .Fields }}
{{- if ne (goType .) "" }}
	{{ goFieldName .Name }} {{ goType . }} // {{ .CppType }} (slot {{ .VTableSlot }})
{{- end }}
{{- end }}
}

func (m *{{ .Name }}) FileIdentifier() uint32 { return {{ .Name }}_FileIdentifier }

func (m *{{ .Name }}) UnmarshalFDB(data []byte) error {
	r, err := wire.NewReader(data)
	if err != nil {
		return err
	}
{{- range .Fields }}
{{- if and (ne .Type "arena") (ne .Type "optional") (ne (readerMethod .) "") }}
	if r.FieldPresent({{ .VTableSlot }}) {
		m.{{ goFieldName .Name }} = r.{{ readerMethod . }}({{ .VTableSlot }})
	}
{{- end }}
{{- end }}
	return nil
}

func (m *{{ .Name }}) MarshalFDB() []byte {
	w := wire.NewWriter(nil)
	return w.WriteMessage({{ .Name }}_FileIdentifier, {{ .Name }}_VTable, {{ maxFieldAlign . }}, func(obj *wire.ObjectWriter) {
{{- range .Fields }}
{{- if and (ne .Type "arena") (ne .Type "optional") (ne (writerMethod .) "") }}
		obj.{{ writerMethod . }}(int({{ $.Name }}_VTable[{{ .VTableSlot }} + 2]), m.{{ goFieldName .Name }})
{{- end }}
{{- end }}
	})
}
`))

func main() {
	schemaDir := flag.String("schema", "pkg/fdbgo/wire/schema", "Directory with schema JSON files")
	outDir := flag.String("out", "pkg/fdbgo/protocol", "Output directory for generated Go files")
	messages := flag.String("messages", "", "Comma-separated list of messages to generate (empty = all)")
	flag.Parse()

	// Load schema files.
	files, err := filepath.Glob(filepath.Join(*schemaDir, "*.json"))
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	filter := make(map[string]bool)
	if *messages != "" {
		for _, m := range strings.Split(*messages, ",") {
			filter[strings.TrimSpace(m)] = true
		}
	}

	os.MkdirAll(*outDir, 0o755)

	count := 0
	for _, f := range files {
		data, err := os.ReadFile(f)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Skip %s: %v\n", f, err)
			continue
		}
		var msg MessageDef
		if err := json.Unmarshal(data, &msg); err != nil {
			fmt.Fprintf(os.Stderr, "Skip %s: %v\n", f, err)
			continue
		}

		if len(filter) > 0 && !filter[msg.Name] {
			continue
		}

		// Skip messages with no fields.
		hasFields := false
		for _, field := range msg.Fields {
			if field.Type != "arena" {
				hasFields = true
				break
			}
		}
		if !hasFields {
			continue
		}

		outPath := filepath.Join(*outDir, strings.ToLower(msg.Name)+".go")
		out, err := os.Create(outPath)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error creating %s: %v\n", outPath, err)
			continue
		}

		if err := messageTmpl.Execute(out, msg); err != nil {
			out.Close()
			fmt.Fprintf(os.Stderr, "Error generating %s: %v\n", msg.Name, err)
			os.Remove(outPath)
			continue
		}
		out.Close()
		count++
	}

	fmt.Fprintf(os.Stderr, "Generated %d Go files in %s\n", count, *outDir)
}
